 @page "/notepad"
 @rendermode InteractiveServer
 @implements IAsyncDisposable
 @inject IJSRuntime JS

 <PageTitle>Notepad</PageTitle>

 <h1>Notepad</h1>

 <textarea class="form-control mb-3" rows="12" @oninput="OnInput" value="@content"></textarea>

 <div class="d-flex align-items-center gap-2 mb-3">
     <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
     <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
     @if (lastSavedAt is not null)
     {
         <span class="text-muted ms-2">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
     }
 </div>

 @code {
     private const string StorageKey = "notepad-content";

     private string content = string.Empty;
     private string savedContent = string.Empty;
     private DateTime? lastSavedAt;
     private IJSObjectReference? module;
     private System.Threading.Timer? autoSaveTimer;

     private bool HasUnsavedChanges => content != savedContent;

     protected override async Task OnAfterRenderAsync(bool firstRender)
     {
         if (!firstRender) return;

         module = await JS.InvokeAsync<IJSObjectReference>(
             "import", "./Components/Pages/Notepad.razor.js");

         var restored = await module.InvokeAsync<string?>("load", StorageKey);
         if (restored is not null)
         {
             content = restored;
             savedContent = restored;
             StateHasChanged();
         }

         autoSaveTimer = new System.Threading.Timer(
             async _ => await InvokeAsync(AutoSaveAsync),
             null,
             TimeSpan.FromSeconds(30),
             TimeSpan.FromSeconds(30));
     }

     private async Task OnInput(ChangeEventArgs e)
     {
         content = e.Value?.ToString() ?? string.Empty;
         if (module is not null)
             await module.InvokeVoidAsync("setUnsaved", HasUnsavedChanges);
     }

     private async Task AutoSaveAsync()
     {
         if (!HasUnsavedChanges || module is null) return;
         await SaveCoreAsync();
         StateHasChanged();
     }

     private async Task SaveNowAsync()
     {
         if (module is null) return;
         await SaveCoreAsync();
     }

     private async Task SaveCoreAsync()
     {
         await module!.InvokeVoidAsync("save", StorageKey, content);
         savedContent = content;
         lastSavedAt = DateTime.Now;
         await module.InvokeVoidAsync("setUnsaved", false);
     }

     private async Task ClearAsync()
     {
         if (module is null) return;
         content = string.Empty;
         savedContent = string.Empty;
         lastSavedAt = null;
         await module.InvokeVoidAsync("clear", StorageKey);
         await module.InvokeVoidAsync("setUnsaved", false);
     }

     public async ValueTask DisposeAsync()
     {
         if (autoSaveTimer is not null)
             await autoSaveTimer.DisposeAsync();

         if (module is not null)
         {
             try
             {
                 await module.InvokeVoidAsync("setUnsaved", false);
             }
             catch (JSDisconnectedException) { }
             await module.DisposeAsync();
         }
     }
 }

